mapper.sql:
tenant_id = #{tenantId} and infrastructure_id = #{infrastructureId}

    and (lower(resource_name) like concat('%', lower(#{keyword}), '%')
     or lower(resource_code) like concat('%', lower(#{keyword}), '%'))

and resource_type = #{resourceType}

mapper.delete:
delete from fp_infrastructure_resource
where tenant_id = #{tenantId}
  and infrastructure_id = #{infrastructureId}
  and last_sync_at != #{lastSyncAt}
